 1→import React, { useMemo } from 'react';
 2→import { parseCanvasDoc } from '../../../../utils/canvasDoc';
 3→import './canvaspreview.css';
 4→
 5→const FONT_MAP = {
 6→    serif: 'Georgia, serif',
 7→    mono: 'Courier New, monospace',
 8→    handwritten: 'Comic Sans MS, cursive',
 9→    bold: 'Trebuchet MS, sans-serif',
10→};
11→
12→const CanvasPreview = ({ canvasDoc }) => {
13→    const parsed = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
14→
15→    const { meta, snippets, images } = parsed;
16→    const isEmpty = snippets.length === 0 && images.length === 0;
17→    const isDark = meta.theme === 'dark';
18→    const aspectClass = meta.aspectRatio === '4:5' ? 'is-4-5' : 'is-1-1';
19→
20→    const allElements = useMemo(() => {
21→        const items = [];
22→
23→        snippets.forEach((s) => {
24→            items.push({ type: 'snippet', zIndex: s.zIndex, data: s });
25→        });
26→
27→        images.forEach((img) => {
28→            items.push({ type: 'image', zIndex: img.zIndex, data: img });
29→        });
30→
31→        items.sort((a, b) => a.zIndex - b.zIndex);
32→        return items;
33→    }, [snippets, images]);
34→
35→    return (
36→        <div
37→            className={`canvas-preview ${isDark ? 'is-dark' : 'is-light'} ${aspectClass}`}
38→            aria-hidden="true"
39→        >
40→            <div className="canvas-preview-dots" />
41→
42→            {isEmpty ? (
43→                <span className="canvas-preview-empty">Canvas</span>
44→            ) : (
45→                allElements.map((el) => {
46→                    if (el.type === 'snippet') {
47→                        const s = el.data;
48→                        const truncated = s.text.length > 80 ? `${s.text.substring(0, 80)}...` : s.text;
49→                        return (
50→                            <span
51→                                key={s.id}
52→                                className="canvas-preview-snippet"
53→                                style={{
54→                                    left: `${s.x * 100}%`,
55→                                    top: `${s.y * 100}%`,
56→                                    zIndex: s.zIndex,
57→                                    fontFamily: FONT_MAP[s.fontStyle] || FONT_MAP.serif,
58→                                    transform: `rotate(${s.rotation}deg) scaleX(${s.scaleX}) scale(${s.sizeScale})`,
59→                                }}
60→                            >
61→                                {truncated}
62→                            </span>
63→                        );
64→                    }
65→
66→                    const img = el.data;
67→                    if (!img.src) return null;
68→                    return (
69→                        <img
70→                            key={img.id}
71→                            className="canvas-preview-image"
72→                            src={img.src}
73→                            alt=""
74→                            loading="lazy"
75→                            draggable={false}
76→                            style={{
77→                                left: `${img.x * 100}%`,
78→                                top: `${img.y * 100}%`,
79→                                width: `${img.width * 100}%`,
80→                                zIndex: img.zIndex,
81→                                transform: `rotate(${img.rotation}deg) scaleX(${img.scaleX})`,
82→                            }}
83→                        />
84→                    );
85→                })
86→            )}
87→        </div>
88→    );
89→};
90→
91→export default CanvasPreview;
