  61→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  62→const createOptimisticId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  63→const toTimestamp = (value) => {
  64→    const parsed = Date.parse(value || "");
  65→    return Number.isNaN(parsed) ? 0 : parsed;
  66→};
  67→const sortByCreatedAt = (a, b) => {
  68→    const byDate = toTimestamp(a?.created_at) - toTimestamp(b?.created_at);
  69→    if(byDate !== 0){
  70→        return byDate;
  71→    }
  72→    return String(a?.id || "").localeCompare(String(b?.id || ""));
