 148→const emojiCanvasCache = new Map();
 149→
 150→const useEmojiImage = (emoji, size) => {
 151→    const [image, setImage] = useState(null);
 152→
 153→    useEffect(() => {
 154→        if(!emoji){
 155→            setImage(null);
 156→            return;
 157→        }
 158→
 159→        const cacheKey = `${emoji}_${size}`;
 160→        if(emojiCanvasCache.has(cacheKey)){
 161→            setImage(emojiCanvasCache.get(cacheKey));
 162→            return;
 163→        }
 164→
 165→        const canvas = document.createElement("canvas");
 166→        const scale = window.devicePixelRatio || 1;
 167→        canvas.width = size * scale;
 168→        canvas.height = size * scale;
 169→        const ctx = canvas.getContext("2d");
 170→        ctx.scale(scale, scale);
 171→        ctx.textAlign = "center";
 172→        ctx.textBaseline = "middle";
 173→        ctx.font = `${size * 0.82}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", "Android Emoji", sans-serif`;
 174→        ctx.fillText(emoji, size / 2, size / 2);
 175→
 176→        const img = new window.Image();
 177→        img.onload = () => {
 178→            emojiCanvasCache.set(cacheKey, img);
 179→            setImage(img);
 180→        };
 181→        img.src = canvas.toDataURL();
 182→    }, [emoji, size]);
 183→
 184→    return image;
 185→};
