 187→const CanvasImageNode = ({canvasImage, stageWidth, stageHeight, onStamp}) => {
 188→    const loadedImage = useLoadedImage(canvasImage?.src);
 189→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 190→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 191→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 192→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 193→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 194→
 195→    return (
 196→        <KonvaImage
 197→            x={x}
 198→            y={y}
 199→            width={objectWidth}
 200→            height={objectHeight}
 201→            image={loadedImage}
 202→            rotation={canvasImage?.rotation || 0}
 203→            scaleX={baseScaleX}
 204→            scaleY={1}
 205→            shadowColor="rgba(0,0,0,0.3)"
 206→            shadowBlur={8}
 207→            shadowOffsetY={3}
 208→            onClick={onStamp}
 209→            onTap={onStamp}
 210→        />
 211→    );
 212→};
