 214→const StampNode = ({stamp, stageWidth, stageHeight, canDelete, onDelete}) => {
 215→    const avatarImage = useLoadedImage(stamp?.user_image_url);
 216→    const icon = STAMP_ICONS[stamp?.stamp_type] || "✨";
 217→    const emojiImage = useEmojiImage(icon, STAMP_SIZE);
 218→    const stampX = clamp((stamp?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - STAMP_SIZE));
 219→    const stampY = clamp((stamp?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - (STAMP_SIZE + PROFILE_SIZE + 10)));
 220→    const avatarCenterX = stampX + (STAMP_SIZE / 2);
 221→    const avatarCenterY = stampY + STAMP_SIZE + (PROFILE_SIZE / 2) + 6;
 222→    const avatarRadius = PROFILE_SIZE / 2;
 223→
 224→    const handleDelete = () => {
 225→        if(canDelete){
 226→            onDelete();
 227→        }
 228→    };
 229→
 230→    return (
 231→        <Group onClick={handleDelete} onTap={handleDelete}>
 232→            <Circle
 233→                x={stampX + (STAMP_SIZE / 2)}
 234→                y={stampY + (STAMP_SIZE / 2)}
 235→                radius={(STAMP_SIZE / 2) + 1.8}
 236→                fill="rgba(255,255,255,0.78)"
 237→                shadowColor="rgba(0,0,0,0.22)"
 238→                shadowBlur={5}
 239→                shadowOffsetY={2}
 240→                listening={false}
 241→            />
 242→            {emojiImage ? (
 243→                <KonvaImage
 244→                    x={stampX}
 245→                    y={stampY}
 246→                    width={STAMP_SIZE}
 247→                    height={STAMP_SIZE}
 248→                    image={emojiImage}
 249→                    listening={false}
 250→                />
 251→            ) : (
 252→                <Text
 253→                    x={stampX}
 254→                    y={stampY}
 255→                    width={STAMP_SIZE}
 256→                    height={STAMP_SIZE}
 257→                    text={icon}
 258→                    fontSize={STAMP_FONT_SIZE}
 259→                    align="center"
 260→                    verticalAlign="middle"
 261→                    listening={false}
 262→                />
 263→            )}
 264→            <Circle
 265→                x={avatarCenterX}
 266→                y={avatarCenterY}
 267→                radius={avatarRadius + 1.2}
 268→                fill="rgba(0,0,0,0.22)"
 269→                listening={false}
 270→            />
 271→            {avatarImage ? (
 272→                <Group
 273→                    clipFunc={(ctx) => {
 274→                        ctx.arc(avatarCenterX, avatarCenterY, avatarRadius, 0, Math.PI * 2, false);
 275→                    }}
 276→                    listening={false}
 277→                >
 278→                    <KonvaImage
 279→                        x={avatarCenterX - avatarRadius}
 280→                        y={avatarCenterY - avatarRadius}
 281→                        width={PROFILE_SIZE}
 282→                        height={PROFILE_SIZE}
 283→                        image={avatarImage}
 284→                        listening={false}
 285→                    />
 286→                </Group>
 287→            ) : (
 288→                <>
 289→                    <Circle
 290→                        x={avatarCenterX}
 291→                        y={avatarCenterY}
 292→                        radius={avatarRadius}
 293→                        fill="#c9d0dc"
 294→                        stroke="rgba(255,255,255,0.95)"
 295→                        strokeWidth={0.7}
 296→                        listening={false}
 297→                    />
 298→                    <Text
 299→                        x={avatarCenterX - avatarRadius}
 300→                        y={avatarCenterY - avatarRadius}
 301→                        width={PROFILE_SIZE}
 302→                        height={PROFILE_SIZE}
 303→                        text={getNameInitial(stamp?.user_name)}
 304→                        fontSize={8}
 305→                        fontStyle="bold"
 306→                        fill="#1f2c3f"
 307→                        align="center"
 308→                        verticalAlign="middle"
 309→                        listening={false}
 310→                    />
 311→                </>
 312→            )}
 313→        </Group>
 314→    );
 315→};
