 317→const CanvasViewer = ({journalId, canvasDoc, authorId}) => {
 318→    const {session, user, openAuthModal} = useAuth();
 319→    const queryClient = useQueryClient();
 320→    const shellRef = useRef(null);
 321→    const stageRef = useRef(null);
 322→    const viewerClientIdRef = useRef(createOptimisticId("canvas-client"));
 323→    const realtimeChannelRef = useRef(null);
 324→    const currentDoodlePointsRef = useRef([]);
 325→    const pendingDoodlePayloadRef = useRef(null);
 326→    const doodleBroadcastTimerRef = useRef(null);
 327→    const lastDoodleBroadcastAtRef = useRef(0);
 328→
 329→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 330→    const [activeStampType, setActiveStampType] = useState("heart");
 331→    const [activeTool, setActiveTool] = useState("stamp");
 332→    const [draggingStampType, setDraggingStampType] = useState("");
 333→    const [isDropActive, setIsDropActive] = useState(false);
 334→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 335→    const [doodleSize, setDoodleSize] = useState(2.8);
 336→    const [isDrawing, setIsDrawing] = useState(false);
 337→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 338→    const [liveDoodlesByClient, setLiveDoodlesByClient] = useState({});
 339→    const [isMobileViewport, setIsMobileViewport] = useState(false);
 340→    const [isMobileDockOpen, setIsMobileDockOpen] = useState(false);
 341→
 342→    const parsedCanvasDoc = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
 343→    const sortedObjects = useMemo(() => {
 344→        const textObjects = (parsedCanvasDoc.snippets || []).map((snippet) => ({
 345→            kind: "snippet",
 346→            payload: {
 347→                ...snippet,
 348→                fontStyle: getLegacyFontStyle(snippet?.fontStyle)
 349→            }
 350→        }));
 351→        const imageObjects = (parsedCanvasDoc.images || []).map((image) => ({kind: "image", payload: image}));
 352→        return [...textObjects, ...imageObjects].sort((a, b) => (a.payload?.zIndex || 0) - (b.payload?.zIndex || 0));
 353→    }, [parsedCanvasDoc.images, parsedCanvasDoc.snippets]);
 354→
 355→    useEffect(() => {
 356→        const getContentWidth = () => {
 357→            const el = shellRef.current;
 358→            if(!el){
 359→                return CANVAS_MAX_WIDTH;
 360→            }
 361→            const style = getComputedStyle(el);
 362→            const paddingLeft = parseFloat(style.paddingLeft) || 0;
 363→            const paddingRight = parseFloat(style.paddingRight) || 0;
 364→            return el.clientWidth - paddingLeft - paddingRight;
 365→        };
 366→
 367→        const updateShellWidth = () => {
 368→            setShellWidth(getContentWidth());
 369→        };
 370→
 371→        updateShellWidth();
 372→        window.addEventListener("resize", updateShellWidth);
 373→
 374→        let resizeObserver = null;
 375→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 376→            resizeObserver = new ResizeObserver(updateShellWidth);
 377→            resizeObserver.observe(shellRef.current);
 378→        }
 379→
 380→        return () => {
 381→            window.removeEventListener("resize", updateShellWidth);
 382→            if(resizeObserver){
 383→                resizeObserver.disconnect();
 384→            }
 385→        };
 386→    }, []);
 387→
 388→    useEffect(() => {
 389→        const mediaQuery = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
 390→        const syncViewport = () => setIsMobileViewport(mediaQuery.matches);
 391→        syncViewport();
 392→
 393→        if(typeof mediaQuery.addEventListener === "function"){
 394→            mediaQuery.addEventListener("change", syncViewport);
 395→            return () => mediaQuery.removeEventListener("change", syncViewport);
 396→        }
 397→
 398→        mediaQuery.addListener(syncViewport);
 399→        return () => mediaQuery.removeListener(syncViewport);
 400→    }, []);
 401→
 402→    useEffect(() => {
 403→        if(isMobileViewport){
 404→            setIsMobileDockOpen(false);
 405→            return;
 406→        }
 407→        setIsMobileDockOpen(true);
 408→    }, [isMobileViewport]);
 409→
 410→    const stageWidth = useMemo(() => Math.max(240, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 411→    const stageHeight = getStageHeight(stageWidth, parsedCanvasDoc?.meta?.aspectRatio);
 412→
 413→    const {data: stampData} = useQuery({
 414→        queryKey: ["canvasStamps", journalId],
 415→        queryFn: () => getCanvasStamps(journalId, session?.access_token),
 416→        enabled: !!journalId,
 417→        refetchOnWindowFocus: false
 418→    });
 419→
 420→    const {data: marginData} = useQuery({
 421→        queryKey: ["canvasMargins", journalId],
 422→        queryFn: () => getCanvasMargins(journalId, session?.access_token),
 423→        enabled: !!journalId,
 424→        refetchOnWindowFocus: false
 425→    });
 426→
 427→    const stampsQueryKey = useMemo(() => ["canvasStamps", journalId], [journalId]);
 428→    const marginsQueryKey = useMemo(() => ["canvasMargins", journalId], [journalId]);
 429→    const currentUserProfile = user?.userData?.[0] || null;
 430→    const currentUserId = currentUserProfile?.id || null;
 431→    const canUseDoodle = Boolean(currentUserId && String(currentUserId) === String(authorId));
 432→
 433→    useEffect(() => {
 434→        if(!canUseDoodle && activeTool === "doodle"){
 435→            setActiveTool("stamp");
 436→            setIsDrawing(false);
 437→            setCurrentDoodlePoints([]);
 438→            currentDoodlePointsRef.current = [];
 439→        }
 440→    }, [activeTool, canUseDoodle]);
 441→
 442→    const getKnownUserProfile = useCallback((targetUserId) => {
 443→        if(!targetUserId){
 444→            return {user_name: null, user_image_url: null};
 445→        }
 446→
 447→        if(currentUserProfile?.id === targetUserId){
 448→            return {
 449→                user_name: currentUserProfile?.name || null,
 450→                user_image_url: currentUserProfile?.image_url || null
 451→            };
 452→        }
 453→
 454→        const knownStamps = queryClient.getQueryData(stampsQueryKey)?.stamps || [];
 455→        const knownMargins = queryClient.getQueryData(marginsQueryKey)?.items || [];
 456→        const match = [...knownStamps, ...knownMargins].find((item) => (
 457→            item?.user_id === targetUserId && (item?.user_name || item?.user_image_url)
 458→        ));
 459→
 460→        return {
 461→            user_name: match?.user_name || null,
 462→            user_image_url: match?.user_image_url || null
 463→        };
 464→    }, [currentUserProfile?.id, currentUserProfile?.image_url, currentUserProfile?.name, marginsQueryKey, queryClient, stampsQueryKey]);
 465→
 466→    const normalizeStampRow = useCallback((row) => {
 467→        if(!row?.id){
 468→            return null;
 469→        }
 470→        const knownProfile = getKnownUserProfile(row.user_id);
 471→        return {
 472→            id: row.id,
 473→            journal_id: row.journal_id,
 474→            user_id: row.user_id,
 475→            snippet_id: row.snippet_id,
 476→            word_key: row.word_key,
 477→            stamp_type: row.stamp_type,
 478→            x: row.x,
 479→            y: row.y,
 480→            created_at: row.created_at,
 481→            user_name: row.user_name ?? knownProfile.user_name ?? null,
 482→            user_image_url: row.user_image_url ?? knownProfile.user_image_url ?? null
 483→        };
 484→    }, [getKnownUserProfile]);
 485→
 486→    const normalizeMarginRow = useCallback((row) => {
 487→        if(!row?.id){
 488→            return null;
 489→        }
 490→        const knownProfile = getKnownUserProfile(row.user_id);
 491→        return {
 492→            id: row.id,
 493→            journal_id: row.journal_id,
 494→            user_id: row.user_id,
 495→            item_type: row.item_type,
 496→            payload: row.payload || null,
 497→            created_at: row.created_at,
 498→            updated_at: row.updated_at,
 499→            user_name: row.user_name ?? knownProfile.user_name ?? null,
 500→            user_image_url: row.user_image_url ?? knownProfile.user_image_url ?? null
 501→        };
 502→    }, [getKnownUserProfile]);
