  14→    handwritten: {label: "Brush Script", fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal", preview: "Wild Brush"},
  15→    bold: {label: "Street Bold", fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold", preview: "Tagline"},
  16→    serifDisplay: {label: "Poster Serif", fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal", preview: "Headline"}
  17→};
  18→
  19→const FONT_STYLE_MAP = {
  20→    serif: "serif",
  21→    handwritten: "handwritten",
  22→    bold: "bold",
  23→    mono: "serif",
  24→    serifDisplay: "serifDisplay"
  25→};
