  5→import { LexicalComposer } from "@lexical/react/LexicalComposer";
  6→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  7→import { useLocation, useNavigate, useParams } from "react-router-dom";
  8→import './contentviewer.css'
  9→import { useEffect, useRef, useState } from "react";
 10→import { AnimatePresence, motion } from "framer-motion";
 11→import { MoonLoader } from "react-spinners";
 12→import CalculateText from "../postCards/calculateReadingTime";
 13→import ParseContent from "../postCards/parseData";
 14→import { useBookMarkMutation, useFollowMutation, useLikeMutation } from "../../../utils/useMutation";
 15→import { useAuth } from "../../../Context/useAuth";
 16→import CommentSection from "../../comments/comments";
 17→import CanvasViewer from "../Canvas/CanvasViewer";
 18→import debounce from "../../../../helpers/debounce";
 19→import formatCounts from "../../../../helpers/fomatCounts";
 20→import { handleClickProfile } from "../../../../helpers/handleClicks";
 21→import { getFollowsData, getJournalById } from "../../../../API/Api";
 22→import { useQuery } from "@tanstack/react-query";
 23→import VerifiedBadge from "../../Badge/VerifiedBadge";
 24→import { getCanvasWholeText, parseCanvasDoc } from "../../../utils/canvasDoc";
 25→
 26→const ContentView = () => {
 27→    const navigate = useNavigate();
 28→    const [showBackButton, setShowBackButton] = useState(true);
 29→    const { session, user } = useAuth();
 30→
 31→    const timeOutRef = useRef();
 32→    const timeOutRefBookmark = useRef();
 33→
 34→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 35→    const [isLiked, setIsliked] = useState('');
 36→    const [likesCount, setLikesCount] = useState(null);
 37→    const [isBookmarked, setIsBookmarked] = useState(null);
 38→    const [bookmarkCounts, setBookmarkCounts] = useState(null);
 39→
 40→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 41→
 42→    const contentRef = useRef();
 43→
 44→    const theme = {
 45→        paragraph: 'editor-paragraph',
 46→        heading: {
 47→            h1: 'editor-heading-h1',
 48→            h2: 'editor-heading-h2',
 49→            h3: 'editor-heading-h3',
 50→        },
 51→        quote: 'editor-quote',
 52→        text: {
 53→            bold: 'editor-text-bold',
 54→            italic: 'editor-text-italic',
 55→            underline: 'editor-text-underline',
 56→        }
 57→    }
 58→
 59→    const location = useLocation();
 60→    const { journalId } = useParams();
 61→    const statePostData = location.state;
 62→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
 63→
 64→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
 65→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
 66→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
 67→        enabled: shouldFetchPost,
 68→        staleTime: 1000 * 60 * 5,
 69→        refetchOnWindowFocus: false,
 70→    });
 71→
 72→    const postData = (() => {
 73→        const journal = fetchedJournalData?.journal;
 74→        if(journal){
 75→            const postType = journal?.post_type || 'text';
 76→            const parsedContent = ParseContent(journal?.content);
 77→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
 78→            const wholeText = postType === 'canvas'
 79→                ? getCanvasWholeText(canvasDoc)
 80→                : (parsedContent?.wholeText || '');
 81→
 82→            return {
 83→                postType: postType,
 84→                content: journal?.content,
 85→                canvasDoc: canvasDoc,
 86→                wholeText: wholeText,
 87→                title: journal?.title,
 88→                userId: journal?.users?.id || journal?.user_id,
 89→                name: journal?.users?.name,
 90→                avatar: journal?.users?.image_url,
 91→                created_at: journal?.created_at,
 92→                journalId: journal?.id,
 93→                isLiked: journal?.has_liked,
 94→                commentsCount: journal?.comment_count?.[0]?.count || 0,
 95→                isBookmarked: journal?.has_bookmarked,
 96→                likesCount: journal?.like_count?.[0]?.count || 0,
 97→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
 98→                badge: journal?.users?.badge
 99→            };
100→        }
101→
102→        if(!statePostData){
103→            return null;
104→        }
105→
106→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
107→        const parsedContent = ParseContent(statePostData?.content);
108→        const canvasDoc = inferredPostType === 'canvas' ? parseCanvasDoc(statePostData?.canvasDoc) : null;
109→
110→        return {
111→            postType: inferredPostType,
112→            content: statePostData?.content,
113→            canvasDoc: canvasDoc,
114→            wholeText: inferredPostType === 'canvas'
115→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
116→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
117→            title: statePostData?.title,
118→            userId: statePostData?.userId,
119→            name: statePostData?.name,
120→            avatar: statePostData?.avatar,
121→            created_at: statePostData?.created_at,
122→            journalId: statePostData?.journalId,
123→            isLiked: statePostData?.isLiked,
124→            commentsCount: statePostData?.commentsCount || 0,
125→            isBookmarked: statePostData?.isBookmarked,
126→            likesCount: statePostData?.likesCount || 0,
127→            bookmarksCount: statePostData?.bookmarksCount || 0,
128→            badge: statePostData?.badge
129→        };
130→    })();
131→
132→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
133→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
134→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
135→        staleTime: 1000 * 60 * 60,
136→        cacheTime: 1000 * 60 * 60,
137→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
138→    });
139→
140→    const handleclickUserProfile = handleClickProfile(navigate);
141→
142→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
143→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
144→        e.stopPropagation();
145→        mutationLike.mutate({ journalId, receiverId, senderImageUrl, sendername, senderEmail });
146→        setLikesCount((prevCount) => (typeof prevCount === 'number' ? prevCount : 0) + (isLiked ? -1 : 1));
147→        setIsliked((prev) => !prev);
148→    }
149→
150→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
151→    const handleClickBookmark = async (e, journalId) => {
152→        e.stopPropagation();
153→        setIsBookmarked(!isBookmarked);
154→        setBookmarkCounts(isBookmarked ? bookmarkCounts - 1 : bookmarkCounts + 1);
155→        const response = await mutationBookmark.mutateAsync({ journalId });
156→        
157→        if(timeOutRefBookmark.current){
158→            clearTimeout(timeOutRefBookmark.current);
159→        }
160→        if (response.message === 'success') {
161→            setBookmarkedMessage('Post was added to your Bookmarks'); 
162→        } else {
163→            setBookmarkedMessage('Post was removed from your Bookmarks');
164→        }
165→            
166→        timeOutRefBookmark.current = setTimeout(() => {
167→            setBookmarkedMessage('');
168→        }, 1500);
169→
170→    }
171→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
172→
173→    const mutationFollow = useFollowMutation(session);
174→    const handleClickFollow = async (e, followingId, followerId) => {
175→        e.stopPropagation();
176→        mutationFollow.mutate({ followingId, followerId });
177→    }
178→    const debounceClickFollow = debounce(handleClickFollow, 100);
179→
180→    const handleBackLocation = (e) => {
181→        e.stopPropagation();
182→        window.history.back();
183→    }
184→
185→    const hanldeClickComments = (e) => {
186→        e.stopPropagation();
187→        setShowCommentsContainer(true);
188→    }
189→
190→    const handleRemixCanvas = (e) => {
191→        e.stopPropagation();
192→        if(!session){
193→            return;
194→        }
195→
196→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
197→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
198→            ? sourceTitle
199→            : `Remix: ${sourceTitle || 'Canvas'}`;
200→
201→        navigate('/home', {
202→            state: {
203→                openEditor: true,
204→                editorMode: 'canvas',
205→                initialTitle: remixTitle,
206→                initialCanvasDoc: postData?.canvasDoc || null,
207→                remixSource: {
208→                    journalId: postData?.journalId,
209→                    authorName: postData?.name || 'Unknown'
210→                }
211→            }
212→        });
213→    }
214→
215→    const handleCLoseComments = () => {
216→        setShowCommentsContainer(false);
217→    }
218→
219→    useEffect(() => {
220→        if (!postData) return;
221→        setLikesCount(postData?.likesCount);
222→        setBookmarkCounts(postData?.bookmarksCount);
223→        setIsliked(postData?.isLiked);
224→        setIsBookmarked(postData?.isBookmarked);
225→    }, [postData]);
226→
227→    useEffect(() => {
228→        if (postData?.title) {
229→            document.title = `${postData.title} | Iskrib`;
230→            return () => {
231→                document.title = 'Iskrib';
232→            };
233→        }
234→
235→        document.title = 'Iskrib';
236→    }, [postData?.title]);
237→
238→    useEffect(() => {
239→        const hideBackBttn = () => {
240→            setShowBackButton(false);
241→            if (timeOutRef.current) {
242→                clearTimeout(timeOutRef.current);
243→            }
244→            timeOutRef.current = setTimeout(() => {
245→                setShowBackButton(true);
246→            }, 300);
247→        }
248→
249→        document.addEventListener('scroll', hideBackBttn, true);
250→        return () => {

400→                            <CanvasViewer
401→                                journalId={postData?.journalId}
402→                                canvasDoc={postData?.canvasDoc}
403→                                authorId={postData?.userId}
404→                            />
405→                        ) : (
406→                            <LexicalComposer initialConfig={{
407→                                namespace: "ContentViewer",
408→                                theme: theme,
409→                                editable: false,
410→                                editorState: postData?.content,
411→                                nodes: [HeadingNode, ImageNode, QuoteNode],
412→                                onError(error) {
413→                                    throw error;
414→                                },
415→                            }}>
416→                                <RichTextPlugin
417→                                    contentEditable={<ContentEditable />}
418→                                    ErrorBoundary={LexicalErrorBoundary}
419→                                />
420→                            </LexicalComposer>
421→                        )}
422→                    </div>
423→                </article>
424→
425→                {/* Toast notification */}
426→            <AnimatePresence>
427→                {bookmarkedMessage && (
428→                    <motion.div
429→                        className="cv-toast"
430→                        initial={{ opacity: 0, y: 8 }}
431→                        animate={{ opacity: 1, y: 0 }}
432→                        exit={{ opacity: 0, y: 8 }}
433→                        transition={{ duration: 0.2, ease: "easeOut" }}
434→                    >
435→                        {bookmarkedMessage}
436→                    </motion.div>
437→                )}
438→            </AnimatePresence>
439→            </div>
440→        </>
441→    )
442→}
443→
444→export default ContentView;
